#!/usr/bin/env python3\n\"\"\"\nScript to update cat-ai-chat-interface.tsx with ReactMarkdown integration\n\"\"\"\n\nimport re\n\ndef update_chat_interface():\n    filepath = 'components/cat-ai-chat-interface.tsx'\n\n    try:\n        with open(filepath, 'r', encoding='utf-8') as f:\n            content = f.read()\n    except FileNotFoundError:\n        print(f\"Error: File not found at {filepath}\")\n        return\n\n    # --- Step 1: Add ReactMarkdown import ---\n    import_statement_to_add = \"import ReactMarkdown from 'react-markdown'\"\n    if import_statement_to_add not in content:\n        # Find the last import statement and insert after it\n        # This regex looks for lines starting with 'import' and captures the last one\n        match = re.search(r'^import .*;\s*$', content, re.MULTILINE)\n        if match:\n            insert_pos = match.end()\n            content = content[:insert_pos] + '\\n' + import_statement_to_add + content[insert_pos:]\n            print(\"✓ Added ReactMarkdown import.\")\n        else:\n            # Fallback: insert at the beginning if no import found (unlikely)\n            content = import_statement_to_add + '\\n' + content\n            print(\"✓ Added ReactMarkdown import at the beginning.\")\n    else:\n        print(\"✓ ReactMarkdown import already exists.\")\n\n    # --- Step 2: Define markdownComponents ---\n    markdown_components = '''\nconst markdownComponents = {\n  h1: ({children}) => (\n    <h1 style={{\n      fontSize: '18px',\n      fontWeight: '600',\n      color: 'white',\n      marginTop: '20px',\n      marginBottom: '10px',\n      letterSpacing: '-0.02em',\n      lineHeight: '1.3'\n    }}>{children}</h1>\n  ),\n  h2: ({children}) => (\n    <h2 style={{\n      fontSize: '16px',\n      fontWeight: '600',\n      color: 'rgba(255,255,255,0.9)',\n      marginTop: '18px',\n      marginBottom: '8px',\n      letterSpacing: '-0.01em'\n    }}>{children}</h2>\n  ),\n  h3: ({children}) => (\n    <h3 style={{\n      fontSize: '14px',\n      fontWeight: '600',\n      color: 'rgba(255,255,255,0.85)',\n      marginTop: '14px',\n      marginBottom: '6px'\n    }}>{children}</h3>\n  ),\n  p: ({children}) => (\n    <p style={{\n      fontSize: '14px',\n      lineHeight: '1.8',\n      color: 'rgba(255,255,255,0.82)',\n      marginTop: '0',\n      marginBottom: '12px'\n    }}>{children}</p>\n  ),\n  strong: ({children}) => (\n    <strong style={{\n      fontWeight: '600',\n      color: 'white'\n    }}>{children}</strong>\n  ),\n  em: ({children}) => (\n    <em style={{\n      fontStyle: 'italic',\n      color: 'rgba(255,255,255,0.7)'\n    }}>{children}</em>\n  ),\n  ul: ({children}) => (\n    <ul style={{\n      paddingLeft: '0',\n      margin: '8px 0 12px 0',\n      listStyle: 'none'\n    }}>{children}</ul>\n  ),\n  ol: ({children}) => (\n    <ol style={{\n      paddingLeft: '20px',\n      margin: '8px 0 12px 0'\n    }}>{children}</ol>\n  ),\n  li: ({children}) => (\n    <li style={{\n      fontSize: '14px',\n      lineHeight: '1.75',\n      color: 'rgba(255,255,255,0.8)',\n      marginBottom: '6px',\n      paddingLeft: '16px',\n      position: 'relative',\n      display: 'flex',\n      alignItems: 'flex-start',\n      gap: '8px'\n    }}>\n      <span style={{\n        display: 'inline-block',\n        width: '5px',\n        height: '5px',\n        borderRadius: '50%',\n        background: '#3B82F6',\n        marginTop: '8px',\n        flexShrink: '0'\n      }}/>\n      <span>{children}</span>\n    </li>\n  ),\n  hr: () => (\n    <hr style={{\n      border: 'none',\n      borderTop: '1px solid rgba(255,255,255,0.08)',\n      margin: '16px 0'\n    }}/>\n  ),\n  blockquote: ({children}) => (\n    <blockquote style={{\n      borderLeft: '2px solid #3B82F6',\n      paddingLeft: '14px',\n      margin: '12px 0',\n      color: 'rgba(255,255,255,0.6)',\n      fontSize: '14px',\n      fontStyle: 'italic'\n    }}>{children}</blockquote>\n  ),\n  code: ({inline, children}) => inline ? (\n    <code style={{\n      background: 'rgba(59,130,246,0.15)',\n      border: '1px solid rgba(59,130,246,0.2)',\n      borderRadius: '4px',\n      padding: '1px 6px',\n      fontSize: '13px',\n      color: '#93C5FD',\n      fontFamily: 'monospace'\n    }}>{children}</code>\n  ) : (\n    <pre style={{\n      background: 'rgba(255,255,255,0.05)',\n      border: '1px solid rgba(255,255,255,0.08)',\n      borderRadius: '8px',\n      padding: '14px 16px',\n      overflow: 'auto',\n      margin: '12px 0'\n    }}>\n      <code style={{\n        fontSize: '13px',\n        color: 'rgba(255,255,255,0.8)',\n        fontFamily: 'monospace',\n        lineHeight: '1.6'\n      }}>{children}</code>\n    </pre>\n  ),\n}\n'''\n\n    # Find insertion point: after the ChatMessage interface definition\n    # This regex looks for the closing brace of the interface and the start of the function\n    match = re.search(r'interface ChatMessage \{[^}]+\}\\n\\nexport default function CatAiChatInterface', content, re.DOTALL)\n    if match:\n        insert_pos = match.start() + len('interface ChatMessage {') # Insert right after the opening brace\n        content = content[:insert_pos] + '\\n' + markdown_components + '\\n' + content[insert_pos:]\n        print(\"✓ Added markdownComponents definition.\")\n    else:\n        print(\"⚠ Could not find the correct insertion point for markdownComponents.\")\n\n    # --- Step 3: Update AI response rendering ---\n    old_ai_response_pattern = re.compile(r'''\n        (                                         # Capture group 1: The existing div and its content\n            <div\n                className=\'text-gray-300 rounded-2xl px-6 py-4 leading-relaxed bg-gradient-to-br from-[#0f1520] to-[#111827] border border-white/10 relative\'\n            >\n                {msg.answer}\n            </div>\n        )\n    ''', re.VERBOSE | re.DOTALL)\n\n    new_ai_response = '''\n            <div\n                className='text-gray-300 rounded-2xl px-6 py-4 leading-relaxed bg-gradient-to-br from-[#0f1520] to-[#111827] border border-white/10 relative'>\n                <ReactMarkdown components={markdownComponents}>\n                    {msg.answer}\n                </ReactMarkdown>\n                <div className='absolute top-0 right-0 p-1'>\n                    <div className='w-2 h-2 bg-green-500/20 rounded-full' />\n                </div>\n            </div>'''\n\n    # Perform the replacement\n    updated_content, num_replacements = old_ai_response_pattern.subn(new_ai_response, content)\n\n    if num_replacements > 0:\n        content = updated_content\n        print(f\"✓ Replaced {num_replacements} instance(s) of AI response rendering.\")\n    else:\n        print(\"⚠ Could not find the AI response rendering pattern to replace.\")\n\n    # --- Write the updated content back to the file ---\n    try:\n        with open(filepath, 'w', encoding='utf-8') as f:\n            f.write(content)\n        print(f\"✓ Successfully updated {filepath}\")\n    except Exception as e:\n        print(f\"Error writing updated content to file: {e}\")\n\nif __name__ == \"__main__\":\n    update_chat_interface()\n    print(\"\\nProcess finished. Please check components/cat-ai-chat-interface.tsx for changes.\")\n